  ('real-estate-moex-01703', 'real-estate', 'real-estate-moex-103-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '有關都市土地、非都市土地的敘述與土地登記謄本運用，下列何者正確？', '["藉由土地登記簿謄本標示部之登載資料，可知該筆土地是否為都市土地或非都市土地", "都市土地係指以土地分區使用計畫及編定各種使用地加以管制", "非都市土地係以土地分區使用計畫對其使用作不同程度之管制", "藉由土地登記簿謄本標示部之登載資料，可知該筆土地之都市土地使用分區"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "64b35f831206", "answer_pdf_sha1": "f925b0123c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01704', 'real-estate', 'real-estate-moex-103-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '老王有兩筆公共設施保留地，A地100 m2及B地150 m2，分別位於桃園縣及苗栗縣，A地為自用住宅使 用，且地上有合法建物為老王所有，供全家居住，B地則未作任何使用並與鄰地隔離，若老王名下只有這 兩筆公共設施保留地，A地當年度公告地價為40,000元/m2，B地當年度公告地價為20,000元/m2，若老 王未申報地價，請問對老王當年度最低應繳之地價稅總額為：', '["免繳地價稅", "6,400元", "8,000元", "3,200元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "64b35f831206", "answer_pdf_sha1": "f925b0123c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01705', 'real-estate', 'real-estate-moex-103-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '徵收土地時，其土地改良物原應一併徵收。但下列情形何者得不受此一限制？', '["墳墓及其他紀念物必須遷移", "依法令規定得建造之建築改良物", "土地改良物所有權人要求取回，並自公告期滿之日起三十日內自行遷移", "農作改良物之種類或數量與正常種植情形不相當者，其全部之農作改良物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "64b35f831206", "answer_pdf_sha1": "f925b0123c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01706', 'real-estate', 'real-estate-moex-103-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '下列有關都市土地徵收田賦之敘述，何者正確？', '["公共設施完竣仍作農業用地使用者", "依法限制建築或不能建築，仍作農業用地使用者", "依都市計畫編為農業區及保護區之所有土地使用者", "依都市計畫編為公共設施保留地之所有土地使用者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "64b35f831206", "answer_pdf_sha1": "f925b0123c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01707', 'real-estate', 'real-estate-moex-103-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '因登記錯誤遺漏或虛偽致受損害者，由該地政機關負損害賠償責任。地政機關應自所收登記費，提存多 少作為登記儲金，專備土地法第68條所定賠償之用？', '["百分之一", "百分之五", "百分之十", "百分之二十"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "64b35f831206", "answer_pdf_sha1": "f925b0123c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01708', 'real-estate', 'real-estate-moex-103-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '土地為信託財產者，下列各款信託關係人間移轉所有權，不課徵土地增值稅之敘述，何者正確？', '["因信託行為成立，委託人與受託人間", "信託關係存續中委託人變更時，原受託人與新受託人間", "因遺囑成立之信託，於信託關係消滅時，受託人與委託人", "信託契約明定信託財產之受益人為委託人者，信託關係消滅時，委託人與受益人間"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "64b35f831206", "answer_pdf_sha1": "f925b0123c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01709', 'real-estate', 'real-estate-moex-103-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '按千分之十計徵地價稅之供事業直接使用之土地，不包括下列那一項？', '["工業用地", "農業用地", "礦業用地", "動物園"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "64b35f831206", "answer_pdf_sha1": "f925b0123c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
