  ('real-estate-moex-01711', 'real-estate', 'real-estate-moex-103-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '下列何者是平均地權條例對以經營土地買賣，違背土地法律，從事土地壟斷、投機者所定之處罰規定？', '["處三年以下有期徒刑，並得併科七千元以上罰金", "處三年以下有期徒刑，並得併科七千元以下罰金", "處三年以上有期徒刑，並得併科七千元以上罰金", "處三年以上有期徒刑，並得併科七千元以下罰金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "64b35f831206", "answer_pdf_sha1": "f925b0123c64", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
